import React from 'react';
import { MessageSquare } from 'lucide-react';

export const PageLoader = () => (
  <div style={{
    minHeight: '100vh', display: 'flex', alignItems: 'center',
    justifyContent: 'center', background: '#f8fafc', flexDirection: 'column', gap: '16px',
  }}>
    <div style={{
      width: '56px', height: '56px', borderRadius: '14px',
      background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      animation: 'pulse 1.5s ease-in-out infinite',
    }}>
      <MessageSquare size={26} color="white" />
    </div>
    <div style={{ color: '#94a3b8', fontSize: '14px' }}>Loading...</div>
    <style>{`@keyframes pulse { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.7;transform:scale(0.95)} }`}</style>
  </div>
);

export const Spinner = ({ size = 20, color = '#6366f1' }) => (
  <div style={{
    width: size, height: size, borderRadius: '50%',
    border: `2px solid ${color}30`,
    borderTopColor: color,
    animation: 'spin 0.7s linear infinite',
    flexShrink: 0,
  }}>
    <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
  </div>
);

export const TableSkeleton = ({ rows = 5, cols = 5 }) => (
  <div style={{ background: 'white', borderRadius: '12px', overflow: 'hidden', border: '1px solid #f1f5f9' }}>
    {Array.from({ length: rows }).map((_, i) => (
      <div key={i} style={{
        display: 'grid', gridTemplateColumns: `repeat(${cols}, 1fr)`,
        gap: '12px', padding: '14px 16px',
        borderBottom: i < rows - 1 ? '1px solid #f8fafc' : 'none',
      }}>
        {Array.from({ length: cols }).map((_, j) => (
          <div key={j} style={{
            height: '14px', borderRadius: '4px',
            background: 'linear-gradient(90deg, #f1f5f9 25%, #e2e8f0 50%, #f1f5f9 75%)',
            backgroundSize: '200% 100%',
            animation: 'shimmer 1.5s infinite',
            width: j === 0 ? '80%' : j === cols - 1 ? '60%' : '100%',
          }} />
        ))}
      </div>
    ))}
    <style>{`@keyframes shimmer { 0%{background-position:200% 0} 100%{background-position:-200% 0} }`}</style>
  </div>
);

export default PageLoader;
